xinshengCustomCss:
@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@300;400;500;700&display=swap');

/* ══════════════════════
   ROOT
══════════════════════ */
.xt-root {
  --xt-bg:         #e8f4fd;
  --xt-text:       #1e4d6e;
  --xt-text-sub:   #5a8faa;
  --xt-text-muted: #9cc4d8;
  --xt-accent:     #4aaee0;
  --xt-accent-bg:  rgba(74,174,224,0.10);
  --xt-border:     #c2e0f4;
  --xt-radius:     18px;
  --xt-radius-sm:  11px;
  --xt-font:       'Noto Sans SC','PingFang SC','Hiragino Sans GB',sans-serif;
  --xt-anim-duration: 0.28s;
  --pink:          #f06292;
  --pink-bg:       #fff0f6;
  --pink-border:   #f8bbd0;
  --pink-text:     #ad1457;
  background: var(--xt-bg);
  padding: 0;
  font-size: 13px;
  line-height: 1.5;
}
.xt-content { padding: 14px 13px 14px; }

/* ══════════════════════
   CARD 通用
══════════════════════ */
.xt-card {
  background: #fff !important;
  border: 1.5px solid #dceefa !important;
  border-radius: 16px !important;
  padding: 0 !important;
  margin-bottom: 10px !important;
  box-shadow: 0 2px 12px rgba(74,174,224,0.07) !important;
  overflow: hidden !important;
}
.xt-card:hover { box-shadow: 0 4px 18px rgba(74,174,224,0.13) !important; transform: none !important; }
.xt-card-title {
  font-size: 10px !important;
  font-weight: 700 !important;
  color: #9cc4d8 !important;
  letter-spacing: 1.2px !important;
  text-transform: uppercase !important;
  padding: 11px 14px 2px !important;
  margin: 0 !important;
  display: block !important;
}

/* ══════════════════════
   最近搜索区
   设计：带标题的独立白卡
   四行搜索词 + 展开心声
══════════════════════ */

/* 四个搜索词共同外包一个白卡效果
   用 search1 第一行的 ::before 做卡片标题 */
.xt-text-search1 {
  margin-top: 0 !important;
  border-radius: 16px 16px 0 0 !important;
  border-bottom: 1px solid #edf6fc !important;
  padding-top: 10px !important;
}
.xt-text-search1::before {
  content: "🔍  最近搜索" !important;
  display: block !important;
  font-size: 10px !important;
  font-weight: 700 !important;
  color: #9cc4d8 !important;
  letter-spacing: 1.2px !important;
  text-transform: uppercase !important;
  margin-bottom: 8px !important;
  padding: 0 !important;
}

/* 四个搜索词的共同样式 */
.xt-text-search1,
.xt-text-search2,
.xt-text-search3,
.xt-text-search4 {
  display: block !important;
  background: #ffffff !important;
  border-left: 1.5px solid #dceefa !important;
  border-right: 1.5px solid #dceefa !important;
  border-top: none !important;
  border-bottom: 1px solid #edf6fc !important;
  border-radius: 0 !important;
  padding: 11px 40px 11px 16px !important;
  margin: 0 !important;
  font-size: 13.5px !important;
  font-weight: 400 !important;
  color: #1e4d6e !important;
  font-style: normal !important;
  cursor: pointer !important;
  position: relative !important;
  transition: background 0.15s !important;
}
/* 左侧搜索图标 */
.xt-text-search1::after,
.xt-text-search2::after,
.xt-text-search3::after,
.xt-text-search4::after {
  content: "›" !important;
  position: absolute !important;
  right: 15px !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
  font-size: 20px !important;
  color: #b8d8ee !important;
  line-height: 1 !important;
  transition: color 0.15s, transform 0.2s !important;
  font-style: normal !important;
}
/* 最后一行圆角收尾（无心声展开时） */
.xt-text-search4 {
  border-radius: 0 0 16px 16px !important;
  border-bottom: 1.5px solid #dceefa !important;
  margin-bottom: 10px !important;
}
/* 展开时最后一行取消圆角，由OS气泡接管 */
#xt-t4:checked ~ .xt-content .xt-text-search4 {
  border-radius: 0 !important;
  border-bottom: 1px solid #edf6fc !important;
}

/* 选中状态高亮 */
#xt-t1:checked ~ .xt-content .xt-text-search1 { background: #f0f9ff !important; color: #0d3a5c !important; }
#xt-t2:checked ~ .xt-content .xt-text-search2 { background: #f0f9ff !important; color: #0d3a5c !important; }
#xt-t3:checked ~ .xt-content .xt-text-search3 { background: #f0f9ff !important; color: #0d3a5c !important; }
#xt-t4:checked ~ .xt-content .xt-text-search4 { background: #f0f9ff !important; color: #0d3a5c !important; }
#xt-t1:checked ~ .xt-content .xt-text-search1::after { color: #4aaee0 !important; transform: translateY(-50%) rotate(90deg) !important; }
#xt-t2:checked ~ .xt-content .xt-text-search2::after { color: #4aaee0 !important; transform: translateY(-50%) rotate(90deg) !important; }
#xt-t3:checked ~ .xt-content .xt-text-search3::after { color: #4aaee0 !important; transform: translateY(-50%) rotate(90deg) !important; }
#xt-t4:checked ~ .xt-content .xt-text-search4::after { color: #4aaee0 !important; transform: translateY(-50%) rotate(90deg) !important; }

/* 搜索心声气泡 */
.xt-text-search1Os,
.xt-text-search2Os,
.xt-text-search3Os,
.xt-text-search4Os {
  display: block !important;
  max-height: 0 !important;
  overflow: hidden !important;
  background: #f5fcff !important;
  border-left: 1.5px solid #dceefa !important;
  border-right: 1.5px solid #dceefa !important;
  border-top: none !important;
  border-bottom: none !important;
  border-radius: 0 !important;
  padding: 0 16px !important;
  margin: 0 !important;
  font-size: 12.5px !important;
  color: #3a7aa0 !important;
  font-style: italic !important;
  line-height: 1.75 !important;
  transition: max-height 0.3s ease, padding 0.22s ease !important;
}
/* search4的Os展开后需要有底部圆角 */
.xt-text-search4Os {
  border-radius: 0 0 16px 16px !important;
  border-bottom: 1.5px solid #dceefa !important;
  margin-bottom: 10px !important;
}
#xt-t1:checked ~ .xt-content .xt-text-search1Os { max-height: 100px !important; padding: 10px 16px 12px !important; }
#xt-t2:checked ~ .xt-content .xt-text-search2Os { max-height: 100px !important; padding: 10px 16px 12px !important; }
#xt-t3:checked ~ .xt-content .xt-text-search3Os { max-height: 100px !important; padding: 10px 16px 12px !important; }
#xt-t4:checked ~ .xt-content .xt-text-search4Os { max-height: 100px !important; padding: 10px 16px 12px !important; }

/* 透明按钮覆盖搜索词行 */
.xt-action-1,.xt-action-2,.xt-action-3,.xt-action-4 {
  display: block !important;
  width: 100% !important;
  height: 44px !important;
  margin: -44px 0 0 0 !important;
  background: transparent !important;
  border: none !important;
  padding: 0 !important;
  cursor: pointer !important;
  position: relative !important;
  z-index: 5 !important;
  opacity: 0 !important;
  font-size: 0 !important;
}
.xt-action-1::after,.xt-action-2::after,
.xt-action-3::after,.xt-action-4::after { content: "" !important; }

/* ══════════════════════
   ROW 两列
══════════════════════ */
.xt-row { gap: 9px !important; margin-bottom: 10px !important; align-items: stretch !important; }
.xt-row > * { margin-bottom: 0 !important; }

/* ── 动物塑 */
.xt-text-animalType {
  display: block !important;
  font-size: 10px !important;
  font-weight: 700 !important;
  color: #4aaee0 !important;
  letter-spacing: 0.8px !important;
  font-style: normal !important;
  padding: 5px 13px 2px !important;
  background: transparent !important;
  border: none !important;
  text-transform: uppercase !important;
}
.xt-text-animalAct {
  display: block !important;
  font-size: 12.5px !important;
  color: #1e4d6e !important;
  font-style: normal !important;
  line-height: 1.8 !important;
  padding: 0 13px 13px !important;
  background: transparent !important;
  border: none !important;
}

/* ── 待办 */
.xt-list { background: transparent !important; padding: 5px 0 8px !important; margin: 0 !important; border-radius: 0 !important; }
.xt-list-item {
  display: flex !important; align-items: center !important; gap: 9px !important;
  font-size: 12.5px !important; color: #1e4d6e !important;
  padding: 7px 14px !important;
  border-bottom: 1px solid #edf6fc !important;
  line-height: 1.4 !important;
}
.xt-list-item:last-child { border-bottom: none !important; }
.xt-list-check {
  width: 15px !important; height: 15px !important;
  border-radius: 5px !important;
  border: 1.5px solid #b8d8ee !important;
  background: #f4faff !important;
  flex-shrink: 0 !important;
}
.xt-list-item-on .xt-list-check { background: #b8d8ee !important; border-color: #4aaee0 !important; }
.xt-list-item-on .xt-list-text { text-decoration: line-through !important; color: #9cc4d8 !important; }
.xt-list-text { font-size: 12.5px !important; color: #1e4d6e !important; font-style: normal !important; }

/* ══════════════════════
   日记横格纸
══════════════════════ */
.xt-quote {
  background: repeating-linear-gradient(
    to bottom,
    transparent 0, transparent 23px,
    #c5e2f2 23px, #c5e2f2 24px
  ) !important;
  border: none !important;
  border-radius: 0 0 14px 14px !important;
  padding: 8px 15px 14px !important;
  margin: 0 !important;
  font-size: 13px !important;
  color: #1e4d6e !important;
  line-height: 24px !important;
  font-style: normal !important;
  box-shadow: none !important;
  min-height: 120px !important;
}
.xt-quote::before,.xt-quote::after { display: none !important; content: none !important; }

/* ══════════════════════
   🔞 浏览历史区
   设计：独立白卡 + 信息流
   平台标签(小) + 标题(大) + OS气泡
══════════════════════ */

/* 整体区域：第一个tag上方加标题 */
.xt-text-nsfw1Tag {
  margin-top: 0 !important;
  border-radius: 16px 16px 0 0 !important;
}
.xt-text-nsfw1Tag::before {
  content: "🔞  浏览历史" !important;
  display: block !important;
  font-size: 10px !important;
  font-weight: 700 !important;
  color: #e07090 !important;
  letter-spacing: 1.2px !important;
  text-transform: uppercase !important;
  padding: 11px 14px 10px !important;
  border-bottom: 1px solid #fce4ec !important;
  margin: 0 -14px 0 -14px !important;
}

/* 平台标签 — 灰色小字，无胶囊 */
.xt-text-nsfw1Tag,
.xt-text-nsfw2Tag,
.xt-text-nsfw3Tag,
.xt-text-nsfw4Tag {
  display: block !important;
  background: #fff !important;
  border-left: 1.5px solid #fce4ec !important;
  border-right: 1.5px solid #fce4ec !important;
  border-top: none !important;
  border-bottom: none !important;
  border-radius: 0 !important;
  padding: 9px 14px 2px !important;
  margin: 0 !important;
  font-size: 10.5px !important;
  font-weight: 400 !important;
  color: #b0c4d0 !important;
  font-style: normal !important;
  position: relative !important;
  letter-spacing: 0.3px !important;
}

/* 标题行 */
.xt-text-nsfw1Title,
.xt-text-nsfw2Title,
.xt-text-nsfw3Title,
.xt-text-nsfw4Title {
  display: block !important;
  background: #fff !important;
  border-left: 1.5px solid #fce4ec !important;
  border-right: 1.5px solid #fce4ec !important;
  border-top: none !important;
  border-bottom: 1px solid #fce4ec !important;
  border-radius: 0 !important;
  padding: 4px 40px 12px 14px !important;
  margin: 0 !important;
  font-size: 13px !important;
  font-weight: 400 !important;
  color: #2a5575 !important;
  font-style: normal !important;
  line-height: 1.6 !important;
  position: relative !important;
  cursor: pointer !important;
  transition: background 0.15s !important;
}
/* 右侧箭头 */
.xt-text-nsfw1Title::after,
.xt-text-nsfw2Title::after,
.xt-text-nsfw3Title::after,
.xt-text-nsfw4Title::after {
  content: "›" !important;
  position: absolute !important;
  right: 14px !important; top: 50% !important;
  transform: translateY(-50%) !important;
  font-size: 20px !important;
  color: var(--pink-border) !important;
  line-height: 1 !important;
  transition: color 0.15s, transform 0.2s !important;
  font-style: normal !important;
}
/* 最后一条标题（无OS展开时）圆角收尾 */
.xt-text-nsfw4Title {
  border-radius: 0 0 16px 16px !important;
  border-bottom: 1.5px solid #fce4ec !important;
  margin-bottom: 10px !important;
}
#xt-t8:checked ~ .xt-content .xt-text-nsfw4Title {
  border-radius: 0 !important;
  border-bottom: 1px solid #fce4ec !important;
  margin-bottom: 0 !important;
}
/* 展开状态箭头旋转 */
#xt-t5:checked ~ .xt-content .xt-text-nsfw1Title { background: #fff8fb !important; }
#xt-t6:checked ~ .xt-content .xt-text-nsfw2Title { background: #fff8fb !important; }
#xt-t7:checked ~ .xt-content .xt-text-nsfw3Title { background: #fff8fb !important; }
#xt-t8:checked ~ .xt-content .xt-text-nsfw4Title { background: #fff8fb !important; }
#xt-t5:checked ~ .xt-content .xt-text-nsfw1Title::after { color: var(--pink) !important; transform: translateY(-50%) rotate(90deg) !important; }
#xt-t6:checked ~ .xt-content .xt-text-nsfw2Title::after { color: var(--pink) !important; transform: translateY(-50%) rotate(90deg) !important; }
#xt-t7:checked ~ .xt-content .xt-text-nsfw3Title::after { color: var(--pink) !important; transform: translateY(-50%) rotate(90deg) !important; }
#xt-t8:checked ~ .xt-content .xt-text-nsfw4Title::after { color: var(--pink) !important; transform: translateY(-50%) rotate(90deg) !important; }

/* OS 气泡 */
.xt-text-nsfw1Os,
.xt-text-nsfw2Os,
.xt-text-nsfw3Os,
.xt-text-nsfw4Os {
  display: block !important;
  max-height: 0 !important;
  overflow: hidden !important;
  background: var(--pink-bg) !important;
  border-left: 1.5px solid var(--pink-border) !important;
  border-right: 1.5px solid var(--pink-border) !important;
  border-top: none !important;
  border-bottom: 1px solid #fce4ec !important;
  border-radius: 0 !important;
  padding: 0 16px !important;
  margin: 0 !important;
  font-size: 12px !important;
  color: #ad1457 !important;
  font-style: italic !important;
  line-height: 1.75 !important;
  transition: max-height 0.3s ease, padding 0.22s ease !important;
}
.xt-text-nsfw4Os {
  border-radius: 0 0 16px 16px !important;
  border-bottom: 1.5px solid var(--pink-border) !important;
  margin-bottom: 10px !important;
}
#xt-t5:checked ~ .xt-content .xt-text-nsfw1Os { max-height: 100px !important; padding: 10px 16px 12px !important; }
#xt-t6:checked ~ .xt-content .xt-text-nsfw2Os { max-height: 100px !important; padding: 10px 16px 12px !important; }
#xt-t7:checked ~ .xt-content .xt-text-nsfw3Os { max-height: 100px !important; padding: 10px 16px 12px !important; }
#xt-t8:checked ~ .xt-content .xt-text-nsfw4Os { max-height: 100px !important; padding: 10px 16px 12px !important; }

/* 透明按钮覆盖标题行 */
.xt-action-5,.xt-action-6,.xt-action-7,.xt-action-8 {
  display: block !important;
  width: 100% !important;
  height: 44px !important;
  margin: -44px 0 0 0 !important;
  background: transparent !important;
  border: none !important;
  padding: 0 !important;
  cursor: pointer !important;
  position: relative !important;
  z-index: 5 !important;
  opacity: 0 !important;
  font-size: 0 !important;
}
.xt-action-5::after,.xt-action-6::after,
.xt-action-7::after,.xt-action-8::after { content: "" !important; }

/* ══════════════════════
   FOOTER
══════════════════════ */
.xt-footer {
  font-size: 10.5px !important;
  color: #9cc4d8 !important;
  text-align: center !important;
  padding: 9px 0 6px !important;
  border-top: 1px dashed #c2e0f4 !important;
  margin-top: 4px !important;
  letter-spacing: 1px !important;
  font-style: normal !important;
}

/* ══════════════════════
   入场动画
══════════════════════ */
@keyframes xtUp {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}
.xt-content > * { animation: xtUp 0.26s ease-out both; }
.xt-content > *:nth-child(1)  { animation-delay: 0.00s; }
.xt-content > *:nth-child(2)  { animation-delay: 0.04s; }
.xt-content > *:nth-child(3)  { animation-delay: 0.08s; }
.xt-content > *:nth-child(4)  { animation-delay: 0.12s; }
.xt-content > *:nth-child(5)  { animation-delay: 0.16s; }
.xt-content > *:nth-child(6)  { animation-delay: 0.20s; }
.xt-content > *:nth-child(7)  { animation-delay: 0.24s; }
.xt-content > *:nth-child(8)  { animation-delay: 0.28s; }
.xt-content > *:nth-child(9)  { animation-delay: 0.32s; }
.xt-content > *:nth-child(10) { animation-delay: 0.36s; }
.xt-content > *:nth-child(11) { animation-delay: 0.40s; }
.xt-content > *:nth-child(12) { animation-delay: 0.44s; }
.xt-content > *:nth-child(13) { animation-delay: 0.48s; }
.xt-content > *:nth-child(14) { animation-delay: 0.52s; }
.xt-content > *:nth-child(15) { animation-delay: 0.56s; }
/* ══════════════════════
   颜文字 footer
══════════════════════ */
.xt-text-footerKao {
  display: block !important;
  text-align: center !important;
  font-size: 13px !important;
  color: #9cc4d8 !important;
  padding: 9px 0 6px !important;
  margin-top: 4px !important;
  border-top: 1px dashed #c2e0f4 !important;
  background: transparent !important;
  border-radius: 0 !important;
  font-style: normal !important;
  letter-spacing: 2px !important;
}

xinshengLayout:
# ── 最近搜索
@text search1
@toggle 1
@text search1Os
@text search2
@toggle 2
@text search2Os
@text search3
@toggle 3
@text search3Os
@text search4
@toggle 4
@text search4Os

# ── 动物塑 + 待办
@row 2
@card "🐾  动物塑"
  @text animalType
  @text animalAct
@endcard

@card "📋  待办备忘"
  @list
    todo1
    todo2
    todo3
    todo4
@endcard
@endrow

# ── 今日日记
@card "✏️  今日日记"
  @quote diary
@endcard

# ── 🔞 浏览历史
@text nsfw1Tag
@text nsfw1Title
@toggle 5
@text nsfw1Os
@text nsfw2Tag
@text nsfw2Title
@toggle 6
@text nsfw2Os
@text nsfw3Tag
@text nsfw3Title
@toggle 7
@text nsfw3Os
@text nsfw4Tag
@text nsfw4Title
@toggle 8
@text nsfw4Os

@text footerKao

